import heapq
from collections import defaultdict
def min_toll(n, edges, s, t):
    g = defaultdict(list)
    for u, v, w in edges:
        g[u].append((v, w))
    INF = 10**18
    dist = [INF] * n
    dist[s] = 0
    pq = [(0, s)]
    while pq:
        d, u = heapq.heappop(pq)
        if d != dist[u]:
            continue
        if u == t:
            return d
        for v, w in g[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                heapq.heappush(pq, (nd, v))
    return -1 if dist[t] >= INF else dist[t]

